</div>undefined</main>undefined<style>
  * {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  main {
    width: 100vw;
    height: 100vh;
    overflow: hidden;
    position: relative;
    background: linear-gradient(-30deg,
        #1b2636,
        #1b2534,
        #1a2433,
        #1a2331,
        #1a222f,
        #1a212e,
        #19202c,
        #191f2a,
        #191e29,
        #181e27,
        #181d25,
        #171c24,
        #171b22,
        #161a21,
        #16191f);
  }

  #titlebar {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    height: var(--height);
    background: var(--surface);
    border-bottom: 0.5px solid var(--border);
    z-index: 10;
  }

  #drag-region {
    height: 100%;
    display: flex;
    align-items: center;
    position: relative;
    --wails-draggable: drag;
  }

  #titlebar-hover-area {
    position: fixed;
    top: calc(var(--height) - 8px);
    left: 0;
    right: 0;
    height: 14px;
    z-index: 11;
    pointer-events: all;
  }

  #window-title {
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    font-size: 11px;
    letter-spacing: 0.12em;
    color: var(--text);
    font-weight: 300;
  }

  #window-title .dim1 {
    color: var(--dim1);
  }

  #window-title .dim2 {
    color: var(--dim2);
  }

  #window-controls {
    position: absolute;
    right: 0;
    top: 0;
    height: 100%;
    display: flex;
  }

  .window-control {
    width: 44px;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 15px;
    color: var(--text);
    cursor: pointer;
  }

  .window-control:hover {
    color: var(--text);
    background: var(--window-icon-hover);
  }

  #close-button:hover {
    color: var(--red);
  }

  #navbar {
    position: fixed;
    top: var(--height);
    left: 0;
    width: var(--width);
    height: calc(100vh - var(--height));
    background: var(--surface);
    border-right: 0.5px solid var(--border);
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    padding: 16px 0;
    z-index: 5;
  }

  .navbar-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
  }

  .divider {
    width: 24px;
    height: 1px;
    background: var(--border);
    margin-bottom: 8px;
  }

  .navbar-button {
    position: relative;
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 8px;
    border: none;
    background: transparent;
    color: var(--navbar-icon);
    cursor: pointer;
  }

  .navbar-button svg {
    width: 18px;
    height: 18px;
    flex-shrink: 0;
  }

  .navbar-button:hover {
    color: var(--navbar-icon-hover);
    background: var(--navbar-icon-hover-bg);
    transform: translateY(-1px);
  }

  .navbar-button:active {
    transform: scale(0.94);
  }

  .navbar-button.active {
    color: var(--accent);
    background: var(--navbar-icon-active);
  }

  .navbar-button .indicator {
    position: absolute;
    left: -1px;
    top: 50%;
    transform: translateY(-50%) scaleY(0);
    width: 2px;
    height: 16px;
    border-radius: 0 2px 2px 0;
    background: var(--accent);
  }

  .navbar-button.active .indicator {
    transform: translateY(-50%) scaleY(1);
  }
</style>
